UPDATE NMCP_QNA_BOARD_BAS
SET DEL_YN = 'Y'
WHERE QNA_SEQ = #{qnaSeq}

mapper.select:
SELECT COUNT(QNA_SEQ) FROM NMCP_QNA_BOARD_BAS WHERE 1=1 AND NVL(DEL_YN, 'N') = 'N'
AND QNA_WRITER_ID = #{qnaWriterID}
AND ANS_STAT_VAL = #{ansStatVal}

SELECT QNA_SEQ, QNA_CTG, (SELECT DTL_CD_NM FROM nmcp_cd_dtl WHERE CD_GROUP_ID = 'QNA' AND DTL_CD = QNA_CTG ) AS QNA_CTG_NM, QNA_NM, QNA_SUBJECT, QNA_CONTENT, QNA_WRITER_ID, TO_CHAR(CRET_DT, 'YYYY.MM.DD') AS CRET_DT, TO_CHAR(AMD_DT, 'YYYY.MM.DD hh24:mi') AS AMD_DT, SMS_SEND_YN, QNA_SMS_SEND_YN, ANS_STAT_VAL, ANS_SUBJECT, ANS_CONTENT, MOBILE_NO, QNA_SUB_CTG_CD FROM NMCP_QNA_BOARD_BAS WHERE 1=1 AND NVL(DEL_YN, 'N') = 'N'
AND QNA_WRITER_ID = #{qnaWriterID}
AND ANS_STAT_VAL = #{ansStatVal}
ORDER BY QNA_SEQ DESC

SELECT COUNT(QNA_SEQ) FROM NMCP_QNA_BOARD_BAS WHERE 1=1 AND NVL(DEL_YN, 'N') = 'N'
AND QNA_WRITER_ID = #{qnaWriterID}
AND ANS_STAT_VAL = #{ansStatVal}

mapper.insert:
INSERT INTO MCP_CALL_QUALITY_AS_LIST
(
	REQ_SEQ
,USER_ID
,CONTRACT_NUM
,CSTMR_NAME
,MOBILE_NO
,ERROR_START_DATE
,ERROR_END_DATE
,ERROR_TYPE_CD
,ERROR_VOICE
,ERROR_CALL
,ERROR_SMS
,ERROR_WIFI
,ERROR_DATA
,ERROR_LOC_TYPE_CD
,CSTMR_POST
,CSTMR_ADDR
,CSTMR_ADDR_DTL
,REG_NM
,REG_MOBILE_NO
,SYS_DT
,REG_DT
,COUNSEL_RSLT_CD
)
VALUES
	(
		MCP_CALL_QUALITY_AS_LIST_SEQ.NEXTVAL
	,#{userId}
	,#{contractNum}
	,#{cstmrName}
	,#{mobileNo}
	,#{errorStartDate}
	,#{errorEndDate}
	,#{errorTypeCd}
	,#{errorVoice}
	,#{errorCall}
	,#{errorSms}
	,#{errorWifi}
	,#{errorData}
	,#{errorLocTypeCd}
	,#{cstmrPost}
	,#{cstmrAddr}
	,#{cstmrAddrDtl}
	,#{regNm}
	,#{regMobileNo}
	,TO_CHAR(SYSDATE,'YYYYMMDD')
	,SYSDATE
	,'R'
	)
